{"action":"created","issue":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/50228","repository_url":"https://api.github.com/repos/JuliaLang/julia","labels_url":"https://api.github.com/repos/JuliaLang/julia/issues/50228/labels{/name}","comments_url":"https://api.github.com/repos/JuliaLang/julia/issues/50228/comments","events_url":"https://api.github.com/repos/JuliaLang/julia/issues/50228/events","html_url":"https://github.com/JuliaLang/julia/issues/50228","id":1765517456,"node_id":"I_kwDOABkWpM5pO6iQ","number":50228,"title":"Parser could detect and warn on common `:1` != Symbol("1") mistake","user":{"login":"BioTurboNick","id":1438610,"node_id":"MDQ6VXNlcjE0Mzg2MTA=","avatar_url":"https://avatars.githubusercontent.com/u/1438610?v=4","gravatar_id":"","url":"https://api.github.com/users/BioTurboNick","html_url":"https://github.com/BioTurboNick","followers_url":"https://api.github.com/users/BioTurboNick/followers","following_url":"https://api.github.com/users/BioTurboNick/following{/other_user}","gists_url":"https://api.github.com/users/BioTurboNick/gists{/gist_id}","starred_url":"https://api.github.com/users/BioTurboNick/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/BioTurboNick/subscriptions","organizations_url":"https://api.github.com/users/BioTurboNick/orgs","repos_url":"https://api.github.com/users/BioTurboNick/repos","events_url":"https://api.github.com/users/BioTurboNick/events{/privacy}","received_events_url":"https://api.github.com/users/BioTurboNick/received_events","type":"User","site_admin":false},"labels":[{"id":163368715,"node_id":"MDU6TGFiZWwxNjMzNjg3MTU=","url":"https://api.github.com/repos/JuliaLang/julia/labels/parser","name":"parser","color":"bfdadc","default":false,"description":"Language parsing and surface syntax"}],"state":"open","locked":false,"assignee":null,"assignees":[],"milestone":null,"comments":3,"created_at":"2023-06-20T14:21:41Z","updated_at":"2023-06-20T19:03:27Z","closed_at":null,"author_associat